import{_ as e,o as r,c as t,a1 as l}from"./chunks/framework.BX4nIuL2.js";const u=JSON.parse('{"title":"Fab 数字化快速原型课程","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/index.md","filePath":"courses/fab-course/index.md"}'),i={name:"courses/fab-course/index.md"};function o(n,a,s,h,c,d){return r(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="fab-数字化快速原型课程" tabindex="-1">Fab 数字化快速原型课程 <a class="header-anchor" href="#fab-数字化快速原型课程" aria-label="Permalink to &quot;Fab 数字化快速原型课程&quot;">​</a></h1><p>数字化快速原型技术（Digital Fabrication &amp; Rapid Prototyping）是将创意具象化为物理实体的必经之路。本课程依托 Fab Lab (数字化制造实验室)，带您深入了解如何通过一系列开源软硬件工具和数字制造设备，实现从“想法”到“原型”的快速迭代。</p><hr><h2 id="🔬-实验室管理与基础" tabindex="-1">🔬 实验室管理与基础 <a class="header-anchor" href="#🔬-实验室管理与基础" aria-label="Permalink to &quot;🔬 实验室管理与基础&quot;">​</a></h2><p>在进入实验室进行物理制造之前，必须熟悉实验室的基本运作规范与安全守则。</p><ul><li><strong>实验室介绍与管理</strong>: <a href="./doc/0manage/labmanage.html">实验室管理规范 (Lab Manage)</a> | <a href="./doc/Fab/FAB.html">Fab Lab 介绍</a> | <a href="./doc/0manage/nexmaker-academy.html">NexMaker 创客学术</a></li><li><strong>安全与工具</strong>: <a href="./doc/0manage/access_safety.html">安全与准入规范 (Access &amp; Safety)</a> | <a href="./doc/0manage/material.html">常用材料指南</a> | <a href="./doc/0manage/tool.html">设备与工具清单</a></li></ul><hr><h2 id="📚-核心教程-tutorials-1-14" tabindex="-1">📚 核心教程 (Tutorials 1-14) <a class="header-anchor" href="#📚-核心教程-tutorials-1-14" aria-label="Permalink to &quot;📚 核心教程 (Tutorials 1-14)&quot;">​</a></h2><p>核心教程分为 14 个核心专题，涵盖了工程项目管理、计算机辅助设计 (CAD)、增减材制造、PCB 电子制造、物联网和人机交互等完整链路：</p><h3 id="🛠️-1-项目管理与网页构建-project-management" tabindex="-1">🛠️ 1. 项目管理与网页构建 (Project Management) <a class="header-anchor" href="#🛠️-1-项目管理与网页构建-project-management" aria-label="Permalink to &quot;🛠️ 1. 项目管理与网页构建 (Project Management)&quot;">​</a></h3><ul><li><strong>核心要求</strong>: <a href="./doc/1projectmanage/Assessment1.html">课程评估规范 (Assessment)</a></li><li><strong>工具与版本控制</strong>: <a href="./doc/1projectmanage/git.html">Git 工具入门</a> | <a href="./doc/1projectmanage/markdown.html">Markdown 语法</a> | <a href="./doc/1projectmanage/imageuploadservice.html">图床服务</a></li><li><strong>网页搭建方法</strong>: <a href="./doc/1projectmanage/github&amp;docsify.html">Github Pages &amp; Docsify</a> | <a href="./doc/1projectmanage/vitepress.html">VitePress 现代静态站</a> | <a href="./doc/1projectmanage/gitbook.html">GitBook 协作</a> | <a href="./doc/1projectmanage/wordpresswebservier.html">WordPress 服务</a> | <a href="./doc/1projectmanage/htmlcssgithub.html">HTML/CSS/Github 技术栈</a> | <a href="./doc/1projectmanage/aigc.html">AIGC 辅助开发</a></li></ul><h3 id="📐-2-计算机辅助设计-cad-design" tabindex="-1">📐 2. 计算机辅助设计 (CAD Design) <a class="header-anchor" href="#📐-2-计算机辅助设计-cad-design" aria-label="Permalink to &quot;📐 2. 计算机辅助设计 (CAD Design)&quot;">​</a></h3><ul><li><strong>核心要求</strong>: <a href="./doc/2cad/Assessment.html">CAD 评估指标</a></li><li><strong>3D 建模实践</strong>: <a href="./doc/2cad/Fusion360prepare.html">Fusion 360 安装与准备</a> | <a href="./doc/2cad/3D_Design_Fusion360.html">Fusion 360 操作指南</a> | <a href="./doc/2cad/Solidworks.html">Solidworks 建模指南</a></li><li><strong>高级建模技巧</strong>: <a href="./doc/2cad/parameterdesign.html">参数化设计 (Parameter Design)</a> | <a href="./doc/2cad/fusion360-sheetmetal.html">钣金件设计 (Sheet Metal)</a> | <a href="./doc/2cad/newdesign.html">AI 辅助生成式设计</a> | <a href="./doc/2cad/practice.html">综合设计实践</a></li></ul><h3 id="🖨️-3-3d-打印技术-3d-printer" tabindex="-1">🖨️ 3. 3D 打印技术 (3D Printer) <a class="header-anchor" href="#🖨️-3-3d-打印技术-3d-printer" aria-label="Permalink to &quot;🖨️ 3. 3D 打印技术 (3D Printer)&quot;">​</a></h3><ul><li><strong>核心要求</strong>: <a href="./doc/3_3dprinter/assessment.html">3D 打印评估指标</a></li><li><strong>FDM 熔融沉积</strong>: <a href="./doc/3_3dprinter/2.FDM3Dprintingbackground.html">FDM 工艺原理</a> | <a href="./doc/3_3dprinter/3.FDM-designguide.html">FDM 设计指南</a> | <a href="./doc/3_3dprinter/4.FDM-machineoperation.html">设备实操与操作规范</a> | <a href="./doc/3_3dprinter/3dprintingdesign.html">FDM 综合实践</a></li><li><strong>其他工艺</strong>: <a href="./doc/3_3dprinter/5.SLAbackground.html">SLA 光固化工艺</a> | <a href="./doc/3_3dprinter/6.sladesignguide.html">SLA 设计指南</a> | <a href="./doc/3_3dprinter/7.hpmjf.html">HP-MJF 尼龙烧结</a></li><li><strong>后期处理与软件</strong>: <a href="./doc/3_3dprinter/8.postprocess.html">3D 打印后处理</a> | <a href="./doc/3_3dprinter/9.3Dslicesoftware.html">主流切片软件使用</a></li></ul><h3 id="⚡-4-电子设计与电路基础-electric-design" tabindex="-1">⚡ 4. 电子设计与电路基础 (Electric Design) <a class="header-anchor" href="#⚡-4-电子设计与电路基础-electric-design" aria-label="Permalink to &quot;⚡ 4. 电子设计与电路基础 (Electric Design)&quot;">​</a></h3><ul><li><strong>核心要求</strong>: <a href="./doc/4electric_design/Assessment.html">电路设计评估指标</a></li><li><strong>电子元器件</strong>: <a href="./doc/4electric_design/electricparameter_component.html">基本电路参数与常用元器件</a> | <a href="./doc/4electric_design/basicknowledge.html">电子电路基础知识</a></li><li><strong>EDA 软件设计</strong>: <a href="./doc/4electric_design/tool.html">EDA 绘图与排版工具</a></li></ul><h3 id="🔌-5-arduino-软硬件应用-arduino-application" tabindex="-1">🔌 5. Arduino 软硬件应用 (Arduino Application) <a class="header-anchor" href="#🔌-5-arduino-软硬件应用-arduino-application" aria-label="Permalink to &quot;🔌 5. Arduino 软硬件应用 (Arduino Application)&quot;">​</a></h3><ul><li><strong>核心要求</strong>: <a href="./doc/5arduino/assessment.html">Arduino 评估指标</a></li><li><strong>开发基础</strong>: <a href="./doc/5arduino/open_source.html">开源硬件理念</a> | <a href="./doc/5arduino/arduino_basic.html">Arduino 基础操作</a> | <a href="./doc/5arduino/arduino_code.html">Arduino 编程语法</a></li><li><strong>传感器与执行器</strong>: <a href="./doc/5arduino/Arduino_Input.html">Arduino 信号输入</a> | <a href="./doc/5arduino/Arduino_output.html">Arduino 控制输出</a></li><li><strong>通信与机械控制</strong>: <a href="./doc/5arduino/processing.html">Processing 互动编程</a> | <a href="./doc/5arduino/robot-mycobot.html">MyCobot 机械臂联合仿真</a></li></ul><h3 id="💥-6-激光切割工艺-laser-cutting" tabindex="-1">💥 6. 激光切割工艺 (Laser Cutting) <a class="header-anchor" href="#💥-6-激光切割工艺-laser-cutting" aria-label="Permalink to &quot;💥 6. 激光切割工艺 (Laser Cutting)&quot;">​</a></h3><ul><li><strong>核心要求</strong>: <a href="./doc/6laser_cutter/Assessment.html">激光切割评估指标</a></li><li><strong>加工规范</strong>: <a href="./doc/6laser_cutter/Safety.html">激光切割安全守则</a> | <a href="./doc/6laser_cutter/AutoCAD.html">AutoCAD 图纸准备</a> | <a href="./doc/6laser_cutter/Design_guide.html">结构设计指南</a> | <a href="./doc/6laser_cutter/Machine_practice.html">激光切割机操作实践</a></li></ul><h3 id="🎛️-7-pcb-制造与焊接工艺-pcb-manufacture" tabindex="-1">🎛️ 7. PCB 制造与焊接工艺 (PCB Manufacture) <a class="header-anchor" href="#🎛️-7-pcb-制造与焊接工艺-pcb-manufacture" aria-label="Permalink to &quot;🎛️ 7. PCB 制造与焊接工艺 (PCB Manufacture)&quot;">​</a></h3><ul><li><strong>焊接与装配</strong>: <a href="./doc/7PCB_manufacture/SMT.html">SMT 表面贴装技术</a> | <a href="./doc/7PCB_manufacture/manual.html">手工焊接技巧与装配规范</a></li></ul><h3 id="⚙️-8-cnc-数控加工工艺-cnc-manufacture" tabindex="-1">⚙️ 8. CNC 数控加工工艺 (CNC Manufacture) <a class="header-anchor" href="#⚙️-8-cnc-数控加工工艺-cnc-manufacture" aria-label="Permalink to &quot;⚙️ 8. CNC 数控加工工艺 (CNC Manufacture)&quot;">​</a></h3><ul><li><strong>核心要求</strong>: <a href="./doc/8CNC_manufacture/Assessment.html">CNC 评估指标</a></li><li><strong>数控编程</strong>: <a href="./doc/8CNC_manufacture/cnctype.html">CNC 常用机器类型</a> | <a href="./doc/8CNC_manufacture/tool.html">桌面级数控刀路规划</a> | <a href="./doc/8CNC_manufacture/cncprogram.html">三轴 CNC 编程入门</a> | <a href="./doc/8CNC_manufacture/cncmanufacture.html">三轴 CNC 设备操作与实操</a></li></ul><h3 id="🧪-9-翻模与铸造-mold" tabindex="-1">🧪 9. 翻模与铸造 (Mold) <a class="header-anchor" href="#🧪-9-翻模与铸造-mold" aria-label="Permalink to &quot;🧪 9. 翻模与铸造 (Mold)&quot;">​</a></h3><ul><li><strong>核心要求</strong>: <a href="./doc/9MOLD/assessment.html">翻模评估指标</a></li><li><strong>模具制作</strong>: <a href="./doc/9MOLD/material.html">硅胶/树脂材料指南</a> | <a href="./doc/9MOLD/tool.html">模具设计工具</a> | <a href="./doc/9MOLD/method.html">翻模铸造标准步骤</a></li></ul><h3 id="🌐-10-物联网与交互设计-iot-interaction" tabindex="-1">🌐 10. 物联网与交互设计 (IoT &amp; Interaction) <a class="header-anchor" href="#🌐-10-物联网与交互设计-iot-interaction" aria-label="Permalink to &quot;🌐 10. 物联网与交互设计 (IoT &amp; Interaction)&quot;">​</a></h3><ul><li><strong>核心要求</strong>: <a href="./doc/10IOT/Assessment.html">物联网评估指标</a></li><li><strong>网络连接</strong>: <a href="./doc/10IOT/IOT_basic.html">物联网基本介绍</a> | <a href="./doc/10IOT/NodeMCUESP8266_ALiYun.html">NodeMCU ESP8266 接入阿里云 IoT</a></li></ul><h3 id="💻-11-界面与交互式应用程序-interface-application" tabindex="-1">💻 11. 界面与交互式应用程序 (Interface Application) <a class="header-anchor" href="#💻-11-界面与交互式应用程序-interface-application" aria-label="Permalink to &quot;💻 11. 界面与交互式应用程序 (Interface Application)&quot;">​</a></h3><ul><li><strong>核心要求</strong>: <a href="./doc/11Interface-application-programming/Assessment.html">交互程序评估指标</a></li><li><strong>界面编程</strong>: <a href="./doc/11Interface-application-programming/processing.html">Processing 基础</a> | <a href="./doc/11Interface-application-programming/processingwitharduino.html">Processing 与 Arduino 串口交互</a> | <a href="./doc/11Interface-application-programming/piying.html">皮影数字交互项目实例</a> | <a href="./doc/11Interface-application-programming/tool.html">其他界面开发工具</a></li></ul><h3 id="🔩-12-标准件与耗材采购-materials-tools" tabindex="-1">🔩 12. 标准件与耗材采购 (Materials &amp; Tools) <a class="header-anchor" href="#🔩-12-标准件与耗材采购-materials-tools" aria-label="Permalink to &quot;🔩 12. 标准件与耗材采购 (Materials &amp; Tools)&quot;">​</a></h3><ul><li><strong>核心要求</strong>: <a href="./doc/12material&amp;tool/assessment.html">标准件与工具选用评估</a></li><li><strong>库房规范</strong>: <a href="./doc/12material&amp;tool/standardcomponentpart.html">常用机械零件与紧固件</a> | <a href="./doc/12material&amp;tool/material.html">常用耗材一览</a></li></ul><h3 id="💼-13-商业计划书基础-business-plan" tabindex="-1">💼 13. 商业计划书基础 (Business Plan) <a class="header-anchor" href="#💼-13-商业计划书基础-business-plan" aria-label="Permalink to &quot;💼 13. 商业计划书基础 (Business Plan)&quot;">​</a></h3><ul><li><strong>核心要求</strong>: <a href="./doc/13BP/assessment.html">商业计划评估指标</a> | <a href="./doc/13BP/README.html">商业孵化指南</a></li></ul><h3 id="🤖-14-智能移动载具开发-ai-vehicle" tabindex="-1">🤖 14. 智能移动载具开发 (AI Vehicle) <a class="header-anchor" href="#🤖-14-智能移动载具开发-ai-vehicle" aria-label="Permalink to &quot;🤖 14. 智能移动载具开发 (AI Vehicle)&quot;">​</a></h3><ul><li><strong>核心要求</strong>: <a href="./doc/14AI&amp;vehicle/assessment.html">智能小车开发评估</a></li><li><strong>控制平台</strong>: <a href="./doc/14AI&amp;vehicle/basic.html">移动机器人底盘开发基础</a> | <a href="./doc/14AI&amp;vehicle/aiplatform.html">AI 自动驾驶算法仿真平台</a></li></ul><hr><h2 id="🎓-年度创新项目与班级档案-fabs" tabindex="-1">🎓 年度创新项目与班级档案 (FABS) <a class="header-anchor" href="#🎓-年度创新项目与班级档案-fabs" aria-label="Permalink to &quot;🎓 年度创新项目与班级档案 (FABS)&quot;">​</a></h2><p>历年来 NexMaker Academy、浙江大学设计工程 (ZJU Design Engineering/Manufacture) 以及 宁波诺丁汉大学 (UNNC FabLab) 课程的学生成果与项目归档：</p><ul><li><strong>UNNC FabLab &amp; Fab Academy</strong>: <ul><li><a href="./class/fab-2025-UNNC.html">Fab Academy 2025 - UNNC 课程归档</a> | <a href="./class/fab-2025-UNNC-2.html">UNNC-FabLab 2025-2 归档</a></li><li><a href="./doc/Fab/fab2023.html">Fab Academy 2023 - Ningbo 成果展示</a></li></ul></li><li><strong>浙江大学设计工程 (ZJU Design Engineering)</strong>: <ul><li><a href="./class/fab-2023-zju-de.html">Design Engineering 2023 专题</a> | <a href="./class/fab-2023-zju-dm.html">Design Manufacture 2023 专题</a> | <a href="./class/fab-2023-zju-mini.html">DE mini 2023</a></li><li><a href="./class/fab-2022-zju-de.html">Design Engineering 2022 专题</a> | <a href="./class/fab-2022-zju-dm.html">Design Manufacture 2022 专题</a> | <a href="./class/fab-2022-zju-mini.html">DE mini 2022</a></li><li><a href="./class/fab-2021-zju-de.html">Design Engineering 2021 专题</a> | <a href="./class/fab-2021-zju-dm.html">Design Manufacture 2021 专题</a></li><li><a href="./class/fab-2020-zju-de.html">Design Engineering 2020 专题</a></li></ul></li><li><strong>浙江万里学院交互系统 (ZWU Interactive System)</strong>: <ul><li><a href="./class/FAB-2026-ZWU-01.html">Interactive System 2026A1 专题</a></li><li><a href="./class/fab-2024-zwu-Interactivesystem.html">Interactive System 2024 课程归档</a> | <a href="./class/fab-2024-zwu-Interactivesystem2+2.html">IS 2+2 2024 归档</a></li></ul></li><li><strong>创客学术归档</strong>: <ul><li><a href="./class/fab-01.html">NexMaker Academy 第 1 期</a> | <a href="./class/fab-02.html">NexMaker Academy 第 2 期</a></li></ul></li></ul><hr><h2 id="🔮-前沿技术探索-others" tabindex="-1">🔮 前沿技术探索 (Others) <a class="header-anchor" href="#🔮-前沿技术探索-others" aria-label="Permalink to &quot;🔮 前沿技术探索 (Others)&quot;">​</a></h2><p>面向下一代混合现实与机器人底盘加工的技术储备：</p><ul><li><strong>XR (扩展现实)</strong>: <a href="./XR/readme.html">XR 概述</a> | <a href="./XR/application_solution.html">行业解决方案</a> | <a href="./XR/brand/aim.html">前沿品牌与生态</a> | <a href="./XR/howtostart.html">快速入门指南</a> | <a href="./XR/xrultrasoudpatent.html">XR 超声技术专利</a> | <a href="./XR/tendency.html">XR 发展趋势与沙龙纪要</a> | <a href="./XR/indusrtstandard.html">行业标准与供应链</a></li><li><strong>AGV (自动导引车)</strong>: <a href="./AGV/readme.html">AGV 底盘概述</a> | <a href="./AGV/agvapplication.html">物流解决方案</a> | <a href="./AGV/agvbrand.html">核心技术品牌</a> | <a href="./AGV/agvhowtostart.html">AGV 开发入门</a> | <a href="./AGV/agvpatent.html">相关技术专利</a> | <a href="./AGV/agvtendency.html">行业演进趋势</a> | <a href="./AGV/agvindusrtstandard.html">AGV 行业标准与供应链</a></li></ul><hr><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>划词对任意章节、实验参数或工艺步骤进行评论，我们的指导教师将会在相应的文档评论区为您解答关于切片层高、热床温度、EDA 拼版或 Arduino 寄存器控制的工艺疑问。</p></div>',47)])])}const f=e(i,[["render",o]]);export{u as __pageData,f as default};
